    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long orig = 0;
        long long maxEven = -1; // B values are non‑negative
        long long minOdd = LLONG_MAX;
        for(int i=1;i<=N;i++){
            long long x; scanf("%lld", &x);
            long long b = llabs(x);
            if(i%2==1){ // odd index, sign +
                orig += b;
                if(b < minOdd) minOdd = b;
            }else{ // even index, sign -
                orig -= b;
                if(b > maxEven) maxEven = b;
            }
        }
        long long diff = maxEven - minOdd;
        if(diff > 0) orig += 2*diff;
        printf("%lld\n", orig);
    }
    return 0;
}

