import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long orig = 0L;
            long maxEven = -1L;
            long minOdd = Long.MAX_VALUE;
            for (int i = 1; i <= N; i++) {
                long x = fs.nextLong();
                long b = Math.abs(x);
                if ((i & 1) == 1) { // odd
                    orig += b;
                    if (b < minOdd) minOdd = b;
                } else { // even
                    orig -= b;
                    if (b > maxEven) maxEven = b;
                }
            }
            long diff = maxEven - minOdd;
            if (diff > 0) orig += 2 * diff;
            sb.append(orig).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            if (c == -1) return null;
            do { sb.append((char)c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

